Here's a production-ready setup using `pg` (node-postgres):

```js
// db.js
const { Pool } = require('pg');

const pool = new Pool({
  host: process.env.PGHOST,
  port: process.env.PGPORT || 5432,
  user: process.env.PGUSER,
  password: process.env.PGPASSWORD,
  database: process.env.PGDATABASE,

  // Pool sizing
  max: 20,                      // max simultaneous clients
  min: 4,                       // keep some warm connections

  // Timeouts
  idleTimeoutMillis: 30000,     // close idle clients after 30s
  connectionTimeoutMillis: 5000,// fail fast if can't get a connection in 5s
  statement_timeout: 10000,     // kill queries running >10s (server-side)
  query_timeout: 10000,         // client-side mirror of the above
  keepAlive: true,              // TCP keepalive, avoids dead-conn hangs

  // TLS (typical for managed Postgres, e.g. RDS/Supabase)
  ssl: process.env.PGSSL === 'true'
    ? { rejectUnauthorized: false }
    : false,
});

// Pool-level error handling — required, or an idle client error
// will crash the process with an uncaught exception.
pool.on('error', (err, client) => {
  console.error('Unexpected error on idle client', err);
  // don't exit process — pool will create a new client as needed
});

pool.on('connect', (client) => {
  // per-connection tuning, runs once per new physical connection
  client.query('SET statement_timeout = 10000');
});

module.exports = pool;
```

Usage with per-query error handling and safe client release:

```js
// queries.js
const pool = require('./db');

async function getUser(id) {
  const client = await pool.connect();
  try {
    const { rows } = await client.query(
      'SELECT * FROM users WHERE id = $1',
      [id]
    );
    return rows[0];
  } catch (err) {
    console.error('Query failed:', err.message);
    throw err;
  } finally {
    client.release(); // always release, even on error
  }
}

// For single queries without manual transaction control,
// prefer pool.query directly — it acquires+releases for you
async function getUserSimple(id) {
  const { rows } = await pool.query('SELECT * FROM users WHERE id = $1', [id]);
  return rows[0];
}

// Transactions
async function transferFunds(fromId, toId, amount) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('UPDATE accounts SET balance = balance - $1 WHERE id = $2', [amount, fromId]);
    await client.query('UPDATE accounts SET balance = balance + $1 WHERE id = $2', [amount, toId]);
    await client.query('COMMIT');
  } catch (err) {
    await client.query('ROLLBACK');
    throw err;
  } finally {
    client.release();
  }
}

module.exports = { getUser, getUserSimple, transferFunds };
```

Graceful shutdown:

```js
process.on('SIGTERM', async () => {
  await pool.end();
  process.exit(0);
});
```

Key points:
- **`pool.on('error', ...)` is mandatory** — without it, a broken idle connection (network blip, server restart) throws an uncaught exception and kills the process.
- **`connectionTimeoutMillis`** stops requests from hanging forever when the pool is exhausted or the DB is unreachable.
- **`statement_timeout`/`query_timeout`** prevent one slow query from holding a connection (and blocking others) indefinitely.
- Always **`client.release()`** in a `finally` block when using `pool.connect()` manually — a missed release leaks a connection from the pool.
- Prefer `pool.query()` for one-off queries; only grab a dedicated client (`pool.connect()`) when you need transactions (`BEGIN`/`COMMIT`) or multiple sequential queries on the same connection.
- Size `max` based on your DB's `max_connections` divided across app instances, not arbitrarily high.

Here's the async/await version, using a promise-based db client (e.g. `mysql2/promise` or similar):

```javascript
async function getUser(id) {
  const [rows] = await db.query('SELECT * FROM users WHERE id = ?', [id]);
  if (!rows.length) throw new Error('Not found');
  return rows[0];
}
```

Usage changes from callback style to:

```javascript
try {
  const user = await getUser(id);
  // use user
} catch (err) {
  // handle error
}
```

Note: this assumes `db.query` returns a promise (as `mysql2/promise`, `pg`, etc. do) and resolves to `[rows, fields]`. If your `db` object is still callback-only (e.g. plain `mysql`), you'd need to either promisify it first or wrap the callback manually:

```javascript
function getUser(id) {
  return new Promise((resolve, reject) => {
    db.query('SELECT * FROM users WHERE id = ?', [id], (err, rows) => {
      if (err) return reject(err);
      if (!rows.length) return reject(new Error('Not found'));
      resolve(rows[0]);
    });
  });
}
```

